//! 全局调度入口：init / per-CPU 状态 / schedule_once / on_timer_tick / idle。
//!
//! 这层把 sched crate 的"系统级状态"集中起来。kernel 启动期调用 [`init`]
//! 建立 init 任务；之后所有 syscall / 内核线程调度都走这里的
//! [`schedule_once`]，定时器中断走 [`on_timer_tick`]。
//!
//! ## 启动期契约
//!
//! [`init`] 必须在 [`crate::arch_hooks::register`] 之后调用——否则 `Task::new`
//! 在分配 ArchContextSlot 时会 panic。本层不强制 arch 注入（保持 libs 层不
//! 依赖 arch crate），由上层 `kernel::sched::boot_init` 负责次序。
//!
//! ## per-CPU 结构
//!
//! [`RUNQUEUES`] / [`CURRENT_TASKS`] / [`IDLE_TASKS`] / [`NEED_RESCHED`] 都是
//! 长度 [`NR_CPUS`] 的数组；用 [`current_cpu_id`] 选当前槽。AP 启动尚未落地，
//! 当前永远只有 CPU 0 被填充。

use alloc::sync::{Arc, Weak};
use alloc::vec::Vec;
use core::sync::atomic::{AtomicBool, AtomicPtr, AtomicU8, AtomicU64, Ordering};

use crate::arch_hooks;
use crate::cpu::{CpuId, CpuMask, MAX_CPUS, SchedPlacement, SchedTopology};
use crate::eevdf::SchedParams;
use crate::group::{ProcessGroup, Session, ThreadGroup};
use crate::ids::Uid;
use crate::pid::PidNamespace;
use crate::runqueue::Runqueue;
use crate::sched_class::SchedAttr;
use crate::signal::{DefaultAction, SigHandler, SigInfo, SignalNumber, default_action};
use crate::sync::Spinlock;
use crate::task::Task;
use crate::{ExitCode, TaskState};

// ── per-CPU 容量 ──────────────────────────────────────────────────────────────

/// 支持的最大 CPU 数。SMP 启动落地之前只有 CPU 0 真正被使用；保留更大数组
/// 是为了让锁顺序、索引代码一次到位，AP 启动接入时无需重排数据结构。
pub const NR_CPUS: usize = MAX_CPUS;

/// 一次调度决策内使用的 runqueue 负载快照。
///
/// 采样时按 CPU 逐个短暂持有 rq 锁，后续选择过程只读本地数组，避免在拓扑
/// 遍历时反复进入不同 rq 锁。快照只保证单次决策内部自洽，不表示全局静态状态。
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub(crate) struct RunqueueLoadSnapshot {
    loads: [usize; NR_CPUS],
}

impl RunqueueLoadSnapshot {
    pub(crate) fn collect<F>(cpus: CpuMask, mut load_of: F) -> Self
    where
        F: FnMut(CpuId) -> usize,
    {
        let sampled = cpus.intersection(CpuMask::SUPPORTED);
        let mut loads = [0; NR_CPUS];
        for cpu in sampled.iter() {
            loads[cpu.get()] = load_of(cpu);
        }
        Self { loads }
    }

    pub(crate) fn load_of(self, cpu: CpuId) -> usize {
        self.loads[cpu.get()]
    }
}

// ── 全局锚点 ──────────────────────────────────────────────────────────────────

/// 每核运行队列。
static RUNQUEUES: [Runqueue; NR_CPUS] = [const { Runqueue::new() }; NR_CPUS];

/// 每核当前正在执行的任务。
static CURRENT_TASKS: [Spinlock<Option<Arc<Task>>>; NR_CPUS] =
    [const { Spinlock::new(None) }; NR_CPUS];

/// 每核当前任务的无所有权热路径指针。
///
/// 指针由 `Arc::into_raw` 发布，槽位自身持有一份强引用；切换 current 时释放旧
/// 指针。这样 syscall/trap 热路径可以不拿 `CURRENT_TASKS` 锁。
static CURRENT_TASK_RAW: [AtomicPtr<Task>; NR_CPUS] =
    [const { AtomicPtr::new(core::ptr::null_mut()) }; NR_CPUS];

/// 每核 idle 任务句柄。`pick_next` 返 None 时 `schedule_once` 切到这里。
static IDLE_TASKS: [Spinlock<Option<Arc<Task>>>; NR_CPUS] =
    [const { Spinlock::new(None) }; NR_CPUS];

/// 每核抢占请求标志。定时器发现 `Runqueue::tick` 需要抢占时置位；trap 返回
/// 路径 / 主动 yield 入口读到 true 即调一次 [`schedule_once`]。
static NEED_RESCHED: [AtomicBool; NR_CPUS] = [const { AtomicBool::new(false) }; NR_CPUS];

/// 已经最终切走的任务。
///
/// Zombie / Dead 任务不会再恢复到自己的内核栈。如果把 `Arc<Task>` 作为普通局部
/// 留在 `schedule_once` 的旧栈上，它的析构永远不会运行，进而保活 VmSpace/FdTable
/// 等资源。最终切换前把它移动到这里，后续任意调度边界在当前活任务栈上 drop。
static RETIRED_TASKS: [Spinlock<Vec<Arc<Task>>>; NR_CPUS] =
    [const { Spinlock::new(Vec::new()) }; NR_CPUS];

static RETIRED_TASKS_NONEMPTY: [AtomicBool; NR_CPUS] = [const { AtomicBool::new(false) }; NR_CPUS];

#[derive(Debug, Clone, Copy, Default)]
pub struct SchedulerDiag {
    pub current_slots: usize,
    pub current_zombie_or_dead: usize,
    pub rq_current_slots: usize,
    pub rq_current_zombie_or_dead: usize,
    pub rq_queued_slots: usize,
    pub rq_queued_zombie_or_dead: usize,
    pub retired_tasks: usize,
    pub pid_count: usize,
    pub init_children: usize,
    pub init_zombies: usize,
}

/// 每核负载拉取请求。其它 CPU 不能直接摘走某个 CPU 的 current，因此只能
/// 通过这个标志让目标 CPU 在调度边界按调度域主动拉取可迁移任务。
static NEED_BALANCE: [AtomicBool; NR_CPUS] = [const { AtomicBool::new(false) }; NR_CPUS];

/// 每核 syscall 收尾后的启动交接轮数。
///
/// clone/fork 成功时只登记这个计数；真正调度发生在 syscall 分发器已经写好
/// 父任务返回值并推进 PC 之后。这样可以给新任务及其 daemon 子进程连续启动
/// 的机会，同时避免在 clone syscall 内部切换导致父 trap frame 尚未收尾。
static POST_SYSCALL_HANDOFF: [AtomicU8; NR_CPUS] = [const { AtomicU8::new(0) }; NR_CPUS];

/// 单次 clone 后让渡的轮数。这里只需要一次安全边界交接：
/// 再多轮只会放大 fork/daemon 一类短任务的 syscall 收尾开销；pthread
/// 创建不走这里，线程会自然运行到 futex 等阻塞点再交给被唤醒者。
const POST_SYSCALL_HANDOFF_ROUNDS: u8 = 1;

struct TimedSleeper {
    deadline_ns: u64,
    task: Weak<Task>,
}

static TIMED_SLEEPERS: Spinlock<Vec<TimedSleeper>> = Spinlock::new(Vec::new());

/// POSIX `ITIMER_REAL` 的纳秒级内核表示。
///
/// `value_ns == 0` 表示当前未 armed；`interval_ns != 0` 表示到期后按该周期重装。
#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
pub struct RealtimeItimerSpec {
    pub value_ns: u64,
    pub interval_ns: u64,
}

struct RealtimeItimer {
    deadline_ns: u64,
    interval_ns: u64,
    thread_group: Weak<ThreadGroup>,
}

static REALTIME_ITIMERS: Spinlock<Vec<RealtimeItimer>> = Spinlock::new(Vec::new());

/// 已上线 CPU 位图。CPU0 在 init 前后始终视为 online；AP 启动后通过
/// [`register_cpu`] 打开对应 bit。
static CPU_ONLINE: AtomicU64 = AtomicU64::new(1);

/// 调度域拓扑。默认只有覆盖全部 CPU 的根域；平台发现更细粒度拓扑后可以在
/// 启动期安装新的域层级。拓扑只用一把独立锁保护，热路径读取后立即释放，
/// 不与 rq 锁嵌套。
static SCHED_TOPOLOGY: Spinlock<SchedTopology> = Spinlock::new(SchedTopology::bootstrap());

/// init 任务全局锚点。写入即 Release，读取必须 Acquire。
static mut INIT_TASK: Option<Arc<Task>> = None;
/// 根 PID namespace。所有任务在分配 pid 时至少在该 ns 中登记一次。
static mut ROOT_PID_NS: Option<Arc<PidNamespace>> = None;
static INIT_READY: AtomicBool = AtomicBool::new(false);

// ── 内部辅助 ──────────────────────────────────────────────────────────────────

/// 当前 CPU id。arch_hooks 未注入时退化为 0（单核场景）。
#[inline]
fn cpu() -> usize {
    let id = arch_hooks::time().map_or(0, |o| (o.current_cpu_id)());
    debug_assert!(id < NR_CPUS, "[sched] cpu id {} >= NR_CPUS", id);
    if id < NR_CPUS { id } else { 0 }
}

fn publish_current_task(cpu_id: usize, task: Arc<Task>) {
    let raw = Arc::into_raw(Arc::clone(&task)) as *mut Task;
    *CURRENT_TASKS[cpu_id].lock() = Some(task);
    let old = CURRENT_TASK_RAW[cpu_id].swap(raw, Ordering::AcqRel);
    if !old.is_null() {
        // Safety: 旧指针由上一轮 `publish_current_task` 的 `Arc::into_raw` 产生。
        unsafe { drop(Arc::from_raw(old)) };
    }
}

pub fn current_cpu_id() -> usize {
    cpu()
}

/// 当前纳秒时间戳。未注入时返回 0，表示"不推进虚拟时间"。
#[inline]
fn now_ns_internal() -> u64 {
    arch_hooks::time().map_or(0, |o| (o.now_ns)())
}

//! EEVDF 调度算法的核心参数与每任务状态。
//!
//! Earliest Eligible Virtual Deadline First (EEVDF) 是 CFS 的继任者，
//! 在保留权重公平性的同时引入"延迟敏感"维度：
//!
//! - **vruntime**：虚拟时间轴上的累计运行量，权重越大走得越慢；
//! - **avg_vruntime**：当前 rq 上所有就绪任务的加权平均，用作"eligible"基线；
//! - **eligible**：`vruntime <= avg_vruntime` 的任务才允许调度；
//! - **deadline**：`vruntime + slice * NICE_0_WEIGHT / weight`，越小越紧迫。
//!
//! 调度决策 = 在所有 eligible 任务中选 deadline 最小者。
//!
//! 离开 rq 时保存 `lag = avg_vruntime - vruntime`，回到 rq 时恢复
//! `vruntime = avg_vruntime - lag`，避免长睡眠任务获得不公平的额度。
//!
//! 本模块只关心**单个任务的 EEVDF 状态**与**算法参数**；rq 级别的
//! `avg_vruntime` 推进与队列结构在 [`crate::runqueue`] 中实现。

use core::sync::atomic::{AtomicBool, AtomicI64, AtomicU8, AtomicU64, Ordering};

use crate::sched_class::{SchedAttr, SchedClass, SchedPolicy};

/// EEVDF 内部使用的权重类型。Linux 中 nice=0 对应 1024。
pub type Weight = u64;

/// `nice == 0` 对应的基准权重。所有相对计算（vruntime 推进、deadline）以此为单位。
pub const NICE_0_WEIGHT: Weight = 1024;

/// 默认基础时间片：6ms（与 Linux `sysctl_sched_base_slice` 同量级）。
pub const DEFAULT_BASE_SLICE_NS: u64 = 6_000_000;

/// nice 值合法范围 `[-20, 19]`。
pub const NICE_MIN: i8 = -20;
pub const NICE_MAX: i8 = 19;

/// 由 nice 推导的权重表。来自 Linux `kernel/sched/core.c::sched_prio_to_weight`。
/// 每相邻两级比率约为 1.25，使得"一级 nice 差"对应大约 10% 的 CPU 份额差异。
const NICE_TO_WEIGHT: [Weight; 40] = [
    88761, 71755, 56483, 46273, 36291, /* nice -20..-16 */
    29154, 23254, 18705, 14949, 11916, /* nice -15..-11 */
    9548, 7620, 6100, 4904, 3906, /* nice -10..-6 */
    3121, 2501, 1991, 1586, 1277, /* nice -5..-1 */
    1024, /* nice 0 */
    820, 655, 526, 423, 335, /* nice 1..5 */
    272, 215, 172, 137, 110, /* nice 6..10 */
    87, 70, 56, 45, 36, /* nice 11..15 */
    29, 23, 18, 15, /* nice 16..19 */
];

/// 把 nice 值钳制到合法区间并换算为 EEVDF 权重。
pub fn weight_from_nice(nice: i8) -> Weight {
    let clamped = nice.clamp(NICE_MIN, NICE_MAX);
    NICE_TO_WEIGHT[(clamped - NICE_MIN) as usize]
}

/// 任务创建 / 属性变更时传入的调度参数。
#[derive(Debug, Clone, Copy)]
pub struct SchedParams {
    /// POSIX nice 值，决定权重。
    pub nice: i8,
    /// 基础时间片（ns）。为 0 时使用 [`DEFAULT_BASE_SLICE_NS`]。
    pub slice_ns: u64,
}

impl SchedParams {
    pub const fn default_fair() -> Self {
        Self {
            nice: 0,
            slice_ns: DEFAULT_BASE_SLICE_NS,
        }
    }

    pub fn weight(&self) -> Weight {
        weight_from_nice(self.nice)
    }

    pub fn slice(&self) -> u64 {
        if self.slice_ns == 0 {
            DEFAULT_BASE_SLICE_NS
        } else {
            self.slice_ns
        }
    }
}

impl From<SchedParams> for SchedAttr {
    fn from(value: SchedParams) -> Self {
        SchedAttr::fair(value.nice, value.slice_ns).normalized()
    }
}

/// 任务的 EEVDF 调度实体状态。
///
/// 字段约定：
///
/// - `weight` 一次性决定后续所有"虚拟时间"推进倍率；调整 nice 时通过
///   [`SchedEntity::set_weight`] 在锁外安全更新（Release，由 rq 重算时 Acquire 读）。
/// - `vruntime` / `deadline` 只在 rq 锁持有下写入，但也提供原子读接口供统计。
/// - `lag` 离开 rq 时保存；重新入队时恢复 `vruntime = avg_vruntime - lag`。
/// - `on_rq` 是观测性标记；权威状态由所在 rq 的索引决定。
pub struct SchedEntity {
    policy: AtomicU8,
    nice: AtomicI64,
    weight: AtomicU64,
    slice_ns: AtomicU64,
    rt_priority: AtomicU8,
    dl_runtime_ns: AtomicU64,
    dl_deadline_ns: AtomicU64,
    dl_period_ns: AtomicU64,
    dl_abs_deadline_ns: AtomicU64,
    dl_replenish_ns: AtomicU64,
    dl_budget_ns: AtomicU64,
    rr_remaining_ns: AtomicU64,
    rq_vruntime: AtomicU64,
    rq_weight: AtomicU64,
    vruntime: AtomicU64,
    deadline: AtomicU64,
    lag: AtomicI64,
    on_rq: AtomicBool,
}

impl SchedEntity {
    pub fn new(params: SchedParams) -> Self {
        let attr = SchedAttr::from(params);
        Self {
            policy: AtomicU8::new(attr.policy as u8),
            nice: AtomicI64::new(attr.nice as i64),
            weight: AtomicU64::new(weight_from_nice(attr.nice)),
            slice_ns: AtomicU64::new(attr.slice_ns),
            rt_priority: AtomicU8::new(attr.priority),
            dl_runtime_ns: AtomicU64::new(attr.runtime_ns),
            dl_deadline_ns: AtomicU64::new(attr.deadline_ns),
            dl_period_ns: AtomicU64::new(attr.period_ns),
            dl_abs_deadline_ns: AtomicU64::new(0),
            dl_replenish_ns: AtomicU64::new(0),
            dl_budget_ns: AtomicU64::new(attr.runtime_ns),
            rr_remaining_ns: AtomicU64::new(attr.slice_ns),
            rq_vruntime: AtomicU64::new(0),
            rq_weight: AtomicU64::new(0),
            vruntime: AtomicU64::new(0),
            deadline: AtomicU64::new(0),
            lag: AtomicI64::new(0),
            on_rq: AtomicBool::new(false),
        }
    }

    pub fn policy(&self) -> SchedPolicy {
        SchedPolicy::from_raw(self.policy.load(Ordering::Acquire)).unwrap_or(SchedPolicy::Fair)
    }

    pub fn class(&self) -> SchedClass {
        self.policy().class()
    }

    pub fn nice(&self) -> i8 {
        self.nice.load(Ordering::Acquire) as i8
    }

    pub fn rt_priority(&self) -> u8 {
        self.rt_priority.load(Ordering::Acquire)
    }

    pub fn sched_attr(&self) -> SchedAttr {
        SchedAttr {
            policy: self.policy(),
            nice: self.nice(),
            slice_ns: self.slice_ns(),
            priority: self.rt_priority(),
            runtime_ns: self.dl_runtime_ns.load(Ordering::Acquire),
            deadline_ns: self.dl_deadline_ns.load(Ordering::Acquire),
            period_ns: self.dl_period_ns.load(Ordering::Acquire),
        }
    }

    pub fn set_sched_attr(&self, attr: SchedAttr) {
        let attr = attr.normalized();
        self.policy.store(attr.policy as u8, Ordering::Release);
        self.nice.store(attr.nice as i64, Ordering::Release);
        self.weight
            .store(weight_from_nice(attr.nice).max(1), Ordering::Release);
        self.slice_ns.store(attr.slice_ns, Ordering::Release);
        self.rt_priority.store(attr.priority, Ordering::Release);
        self.dl_runtime_ns.store(attr.runtime_ns, Ordering::Release);
        self.dl_deadline_ns
            .store(attr.deadline_ns, Ordering::Release);
        self.dl_period_ns.store(attr.period_ns, Ordering::Release);
        self.dl_abs_deadline_ns.store(0, Ordering::Release);
        self.dl_replenish_ns.store(0, Ordering::Release);
        self.dl_budget_ns.store(attr.runtime_ns, Ordering::Release);
        self.rr_remaining_ns.store(attr.slice_ns, Ordering::Release);
    }

    pub fn weight(&self) -> Weight {
        self.weight.load(Ordering::Acquire)
    }

    pub fn set_weight(&self, w: Weight) {
        self.weight.store(w.max(1), Ordering::Release);
    }

//! 基于伙伴算法的物理页分配器。
//!
//! 这个模块管理“真正的物理页帧”。如果把整个 allocator 看成分层系统，那么它位于
//! 最底层，向上给虚拟地址空间、kernel heap、slab 和其它组件提供页级内存来源。
//!
//! 当前实现的几个关键目标是：
//!
//! - 支持多个物理内存段，而不是假设整块连续 RAM；
//! - 支持按 order 管理和合并页块，降低外部碎片；
//! - 支持不同 free list / zone，例如默认区和低端 DMA 区；
//! - 支持精确物理地址放置与大页对齐策略，满足内核映射需求。
//!
//! “segment-aware” 的意思是，分配器不会把所有 RAM 简化成单一线性池，而是保留
//! 来自 DTB/固件解析的段信息，并在每个 zone 中分别维护伙伴结构。这一点对真实平台
//! 很重要，因为可用内存通常并不天然连续，而且还可能夹杂保留区、DMA 约束区和设备
//! 窗口。

use core::alloc::Layout;
use core::mem::size_of;
use core::ptr::null_mut;

use crate::boot::BootAllocator;
use crate::request::{
    AllocationRequestError, MemoryPlacement, PhysicalAllocRequest, PhysicalAllocation,
};

#[inline]
fn now_ns() -> u64 {
    log::get_timestamp_ns()
}

#[inline]
fn elapsed_us(start_ns: u64) -> u64 {
    now_ns().saturating_sub(start_ns) / 1_000
}

/// 基本页大小：4 KiB。
pub const PAGE_SIZE: usize = 4096;
/// 基本页偏移位数。
#[allow(dead_code)]
pub const PAGE_SHIFT: usize = 12;
/// 当前机器字长下最大可追踪的 order 值。
///
/// `order` 会被频繁换算成字节大小 `(1 << order) * PAGE_SIZE`；保留最高位可以
/// 保证这个乘法始终落在 `usize` 可表示范围内，避免最大 order 在不同构建模式下
/// 触发溢出或回绕。
pub const MAX_TRACKED_ORDER: usize = usize::BITS as usize - PAGE_SHIFT - 1;
/// 按用途拆分的空闲链表数量。
pub const VM_NFREELIST: usize = 2;
/// 默认空闲链表索引。
pub const VM_FREELIST_DEFAULT: usize = 0;
/// 低端 DMA 空闲链表索引。
pub const VM_FREELIST_DMA: usize = 1;
/// DMA 区域边界（16 MiB）。
pub const DMA_ZONE_LIMIT: usize = 16 * 1024 * 1024;
/// 默认物理区保留的 order-0 热页数量。
///
/// page alloc/free 的高频路径如果每次释放都立即向上合并，下一次分配又会把大块重新
/// split 成 4K 页。保留一个很小的 order-0 自然 free-list 水位，可以降低这种
/// split/merge 抖动；上限保持在 512KiB，避免长期牺牲高阶连续页。
pub(crate) const DEFERRED_ORDER0_COALESCE_TARGET: usize = 128;
/// 物理内存低于该空闲百分比时禁用延迟合并，优先恢复大块连续空间。
pub(crate) const DEFERRED_ORDER0_MIN_FREE_PERCENT: usize = 25;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct MemorySegment {
    pub start: usize,
    pub size: usize,
}

impl MemorySegment {
    pub const fn end(self) -> usize {
        self.start.saturating_add(self.size)
    }
}

#[derive(Clone, Copy, PartialEq, Eq, Debug)]
#[repr(u8)]
pub enum PageState {
    Free = 0,
    Allocated = 1,
    BuddyTail = 2,
    Reserved = 3,
}

/// 兼容旧接口保留的页描述符类型。
///
/// 稀疏实现不再为整机 RAM 物化全局 `PageInfo[]`；因此 `page_info()/iter_pages()`
/// 这类“按页遍历”接口仅保留 ABI/编译兼容性，不再作为主路径数据源。
#[derive(Clone, Copy)]
pub struct PageInfo {
    pub free_next: u32,
    pub free_prev: u32,
    pub ref_count: u16,
    #[allow(dead_code)]
    pub slab_zone_id: u16,
    pub state: PageState,
    pub order: u8,
    #[allow(dead_code)]
    pub gc_mark: u8,

//! 小对象 slab 分配器。
//!
//! 这个模块负责高频、小尺寸对象的分配与释放，是内核常规 `Box`、小型结构体、缓存
//! 节点等对象最常走的路径。它的设计目标是：
//!
//! - 小对象分配足够快，避免频繁落到页级分配；
//! - 同尺寸对象集中放置，减少内部碎片；
//! - 借助每 CPU 缓存降低锁竞争和跨核共享压力。
//!
//! 实现思路接近经典的 slab/UMA：
//!
//! - 先把常用小尺寸离散成若干 size class；
//! - 每个 size class 维护自己的 slab 链表；
//! - slab 由一批页组成，再切分成若干固定大小对象槽；
//! - 热路径优先命中 per-CPU cache，缓存失配时再回到全局状态补货。
//!
//! 它和 `kheap` 的分工边界很明确：不适合放进 slab 的对象，直接交给大对象路径。
