#[derive(Clone, Copy)]
struct CacheEntry {
    ptr: usize,
    slab_node: usize,
}

impl CacheEntry {
    const fn empty() -> Self {
        Self {
            ptr: 0,
            slab_node: INVALID_SLAB_NODE,
        }
    }
}

