pub struct SigSet(pub u64);

impl SigSet {
    pub const EMPTY: Self = Self(0);
    pub const fn has(self, sig: SignalNumber) -> bool {
        (self.0 & sig.bit()) != 0
    }
    pub const fn with(self, sig: SignalNumber) -> Self {
        Self(self.0 | sig.bit())
