// ── Log sink line buffer ──────────────────────────────────────────────────────

const SINK_LINE_BUFFER_SIZE: usize = 1280;

pub(crate) struct SinkLineBuffer {
    buf: [u8; SINK_LINE_BUFFER_SIZE],
    len: usize,
}

impl SinkLineBuffer {
    pub(crate) const fn new() -> Self {
        Self {
            buf: [0; SINK_LINE_BUFFER_SIZE],
            len: 0,
        }
    }

    pub(crate) fn as_bytes(&self) -> &[u8] {
        &self.buf[..self.len]
    }
}

impl fmt::Write for SinkLineBuffer {
    fn write_str(&mut self, s: &str) -> fmt::Result {
        if self.len >= self.buf.len() {
            return Ok(());
        }
        let available = self.buf.len() - self.len;
        let copy_len = s.len().min(available);
        self.buf[self.len..self.len + copy_len].copy_from_slice(&s.as_bytes()[..copy_len]);
        self.len += copy_len;
        Ok(())
    }
}

pub(crate) fn format_log_record_line(record: &log::LogRecord<'_>) -> SinkLineBuffer {
    let (secs, nanos) = log::format_timestamp(record.timestamp);
    let mut buf = SinkLineBuffer::new();
    let _ = writeln!(
        &mut buf,
        "[{:6}.{:06}] {}",
        secs,
        nanos / 1000,
        record.message
    );
    buf
}

// ── Memory segment helpers ────────────────────────────────────────────────────

pub(crate) fn normalize_memory_segments(
    mut segments: Vec<MemorySegment>,
) -> Option<Vec<MemorySegment>> {
    if segments.is_empty() {
        return None;
    }
    segments.sort_unstable_by_key(|s| s.start);
    let mut merged: Vec<MemorySegment> = Vec::with_capacity(segments.len());
    for seg in segments {
        if seg.size == 0 {
            continue;
        }
        if let Some(last) = merged.last_mut() {
            let last_end = last.start.saturating_add(last.size);
            if last_end >= seg.start {
                let merged_end = last_end.max(seg.start.saturating_add(seg.size));
                last.size = merged_end.saturating_sub(last.start);
                continue;
            }
        }
        merged.push(seg);
    }
    (!merged.is_empty()).then_some(merged)
}

//! ext4 extent tree 遍历(只读)。
//!
//! Extent 是 ext4 的稀疏稀释映射:每 12 字节描述一段连续逻辑块 → 物理块。
//! `i_block[0..60]` 先放一个 `ext4_extent_header`,后面按情况紧接叶节点
//! (ext4_extent)或内节点(ext4_extent_idx)。磁盘上深度 > 0 的子节点各占一整块。
//!
//! 布局:
//!
//! ```text
//! +----------- ext4_extent_header (12 bytes) -----------+
//! | magic(2) | entries(2) | max(2) | depth(2) | gen(4) |
//! +-----------------------------------------------------+
//! ```
//!
//! depth == 0:后面跟 entries 个 ext4_extent(12 字节)
//! depth  > 0:后面跟 entries 个 ext4_extent_idx(12 字节)

use alloc::vec;
use alloc::vec::Vec;

use crate::layout::EXT4_EXT_MAGIC;
use crate::state::{BlockBackendError, FsState};

const EXT_HEADER_SIZE: usize = 12;
const EXT_ENTRY_SIZE: usize = 12;

#[inline(always)]
fn read_u32_le(p: *const u8, off: usize) -> u32 {
    u32::from_le_bytes(unsafe {
        [
            *p.add(off),
            *p.add(off + 1),
            *p.add(off + 2),
            *p.add(off + 3),
        ]
    })
}

#[inline(always)]
fn read_u16_le(p: *const u8, off: usize) -> u16 {
    u16::from_le_bytes(unsafe { [*p.add(off), *p.add(off + 1)] })
}

#[derive(Debug, Clone, Copy)]
struct ExtHeader {
    entries: u16,
    depth: u16,
}

#[inline]
fn parse_header(buf: &[u8]) -> Option<ExtHeader> {
    if buf.len() < EXT_HEADER_SIZE {
        return None;
    }
    let p = buf.as_ptr();
    let magic = read_u16_le(p, 0);
    if magic != EXT4_EXT_MAGIC {
        return None;
    }
    let entries = read_u16_le(p, 2);
    let depth = read_u16_le(p, 6);
    Some(ExtHeader { entries, depth })
}

/// 根据逻辑块号 `logical_block` 找对应的物理块号。若存在"洞",返回 `Ok(None)`。
///
/// `root` 是 `inode.i_block[0..60]`(或任何内节点块的前 60 字节)的副本;
/// 递归下钻时会从 `state` 按需读取子节点块。
#[inline]
pub(crate) fn map_block(
    state: &FsState,
    root: &[u8],
    logical_block: u32,
) -> Result<Option<u64>, BlockBackendError> {
    let mut current: alloc::vec::Vec<u8> = alloc::vec::Vec::from(root);
    loop {
        let hdr = match parse_header(&current) {
            Some(h) => h,
            None => return Ok(None),
        };

